const rows=$input.all().map(i=>i.json);
return rows.map(r=>{
  const notes=r.notes||'';
  const prompt='You are refining the Tecknuovo second-brain signal classifier for the account "'+(r.account||'')+'".\n'
    +'Below are human corrections to signals we generated for this account (most recent first). '
    +'Distil them into 3-5 short, imperative lessons the classifier should apply next time '
    +'(e.g. "Do not flag routine status updates as risks"; "Budget mentions under 50k are not opportunities"). '
    +'Be specific to the patterns you actually see. Return ONLY the bullet lessons, no preamble.\n\nCORRECTIONS:\n'+notes;
  return {json:{account_id:r.account_id,account:r.account,prompt}};
});

const e=s=>String(s==null?'':s).replace(/'/g,"''");
const summary=($json.text||$json.response||$json.output||'').trim();
const accId=$('Build prompt').item.json.account_id;
if(!summary||!accId){return [];}
const sql="UPDATE accounts SET feedback_summary='"+e(summary)+"' WHERE id='"+e(accId)+"';";
return [{json:{sql,account_id:accId,chars:summary.length}}];
